class LRUCache {
  constructor(cap) {
    this.cap = cap;
    this.map = new Map(); // key → node
    // Sentinel head/tail
    this.head = { key:0, val:0, prev:null, next:null };
    this.tail = { key:0, val:0, prev:this.head, next:null };
    this.head.next = this.tail;
  }
  _remove(n) { n.prev.next = n.next; n.next.prev = n.prev; }
  _add(n) { n.prev = this.head; n.next = this.head.next; this.head.next.prev = n; this.head.next = n; }
  get(k) {
    if (!this.map.has(k)) return -1;
    const n = this.map.get(k); this._remove(n); this._add(n); return n.val;
  }
  put(k, v) {
    if (this.map.has(k)) this._remove(this.map.get(k));
    const n = { key:k, val:v }; this._add(n); this.map.set(k, n);
    if (this.map.size > this.cap) { const old = this.tail.prev; this._remove(old); this.map.delete(old.key); }
  }
}
// Time: O(1) get/put  Space: O(capacity)

function wordBreak(s, wordDict) {
  const set = new Set(wordDict);
  const dp = new Array(s.length + 1).fill(false);
  dp[0] = true;
  for (let i = 1; i <= s.length; i++)
    for (let j = 0; j < i; j++)
      if (dp[j] && set.has(s.slice(j, i))) { dp[i] = true; break; }
  return dp[s.length];
}
