function threeSum(nums) {
  nums.sort((a,b) => a-b);
  const res = [];
  for (let i = 0; i < nums.length - 2; i++) {
    if (i > 0 && nums[i] === nums[i-1]) continue;
    let l = i+1, r = nums.length-1;
    while (l < r) {
      const sum = nums[i]+nums[l]+nums[r];
      if (sum === 0) { res.push([nums[i],nums[l],nums[r]]); while (nums[l]===nums[l+1]) l++; while (nums[r]===nums[r-1]) r--; l++; r--; }
      else if (sum < 0) l++;
      else r--;
    }
  }
  return res;
}
// Time: O(n²)  Space: O(1)

function trap(height) {
  let l = 0, r = height.length-1, ml = 0, mr = 0, water = 0;
  while (l < r) {
    if (height[l] < height[r]) { ml = Math.max(ml, height[l]); water += ml - height[l]; l++; }
    else { mr = Math.max(mr, height[r]); water += mr - height[r]; r--; }
  }
  return water;
}
// Time: O(n)  Space: O(1)

function maxSlidingWindow(nums, k) {
  const deque = [], res = [];
  for (let i = 0; i < nums.length; i++) {
    while (deque.length && deque[0] < i-k+1) deque.shift();
    while (deque.length && nums[deque[deque.length-1]] < nums[i]) deque.pop();
    deque.push(i);
    if (i >= k-1) res.push(nums[deque[0]]);
  }
  return res;
}
// Time: O(n)  Space: O(k)

function mergeKLists(lists) {
  function merge2(a, b) {
    const dummy = {}; let cur = dummy;
    while (a && b) { if (a.val <= b.val) { cur.next = a; a = a.next; } else { cur.next = b; b = b.next; } cur = cur.next; }
    cur.next = a || b;
    return dummy.next;
  }
  if (!lists.length) return null;
  while (lists.length > 1) {
    const merged = [];
    for (let i = 0; i < lists.length; i += 2) merged.push(merge2(lists[i], lists[i+1] || null));
    lists = merged;
  }
  return lists[0];
}
// Time: O(n·log k)  Space: O(1)

function canFinish(n, pre) {
  const adj = Array.from({length:n}, ()=>[]);
  pre.forEach(([a,b]) => adj[b].push(a));
  const state = new Array(n).fill(0); // 0=unseen,1=visiting,2=done
  function dfs(node) {
    if (state[node] === 1) return false;
    if (state[node] === 2) return true;
    state[node] = 1;
    for (const nb of adj[node]) if (!dfs(nb)) return false;
    state[node] = 2;
    return true;
  }
  for (let i = 0; i < n; i++) if (!dfs(i)) return false;
  return true;
}
