class EventEmitter {
  constructor() { this.events = new Map(); }
  on(evt, fn) {
    if (!this.events.has(evt)) this.events.set(evt, []);
    this.events.get(evt).push(fn);
    return this;
  }
  off(evt, fn) {
    const listeners = this.events.get(evt) || [];
    this.events.set(evt, listeners.filter(l => l !== fn));
    return this;
  }
  emit(evt, ...args) {
    (this.events.get(evt) || []).forEach(fn => fn(...args));
    return this;
  }
}
// Foundation for Node.js EventEmitter

